class Counter {
    // Instance variable — each object has its own
    int instanceCount = 0;

    // Static variable — SHARED across all objects
    static int staticCount = 0;

    // Static final constant (common pattern)
    static final double PI = 3.14159;

    Counter() {
        instanceCount++;
        staticCount++;
        System.out.println("Object created! Instance: " + instanceCount + 
                         ", Static total: " + staticCount);
    }

    // Instance method
    void displayInstance() {
        System.out.println("Instance count for this object: " + instanceCount);
    }

    // Static method
    static void displayStatic() {
        System.out.println("Total objects created: " + staticCount);
        // Can't access instance variables here!
        // System.out.println(instanceCount); // ERROR!
    }
}

public class StaticExample {
    // Static block — runs when class loads
    static {
        System.out.println("Static block runs once when class loads");
    }

    public static void main(String[] args) {
        // Accessing static members without objects
        System.out.println("PI: " + Counter.PI);
        Counter.displayStatic();

        System.out.println("--- Creating objects ---");
        Counter c1 = new Counter();
        Counter c2 = new Counter();
        Counter c3 = new Counter();

        // Accessing instance members
        c1.displayInstance();
        c2.displayInstance();

        // Static member is shared
        Counter.displayStatic();

        // Math class — all static
        System.out.println("Math.PI: " + Math.PI);
        System.out.println("Math.sqrt(16): " + Math.sqrt(16));
        System.out.println("Math.pow(2, 3): " + Math.pow(2, 3));
    }
}

