phase3.solution:
class Student {
    String name;
    int grade;
    static String schoolName;

    static void setSchoolName(String name) {
        schoolName = name;
    }

    Student(String name, int grade) {
        this.name = name;
        this.grade = grade;
    }

    void displayInfo() {
        System.out.println("Name: " + name + ", Grade: " + grade + 
                         ", School: " + schoolName);
    }
}

public class Main {
    public static void main(String[] args) {
        Student.setSchoolName("MIT");

        Student s1 = new Student("Alice", 11);
        Student s2 = new Student("Bob", 12);
        Student s3 = new Student("Charlie", 10);

        s1.displayInfo();
        s2.displayInfo();
        s3.displayInfo();
    }
}
